import React                    from "react";
import './Research.css'
import logo                                      from "../../assets/placeholder.png"
import {Box, Paper, Skeleton, Stack, Typography} from "@mui/material";


// eslint-disable-next-line @typescript-eslint/no-unused-vars
function ResearchViewComponent() {
    return (
    <Paper sx={{borderRadius: "8px"}}>
        <Box sx={{maxWidth:"fit-content"}}>
            <Stack id="researchContent" direction="column" spacing={1}>
                <a id="researchImage" href="#researchSegment"><img src={logo} alt=""/></a>
                <Typography sx={{fontWeight: "bold", color: "secondary.main", m:0}} align="left" variant="h4">Project Name</Typography>
                <Typography
                    sx={{color: "text.primary", textAlign:"justify", maxHeight: "200px", maxWidth:"256px", overflow: "hidden", textOverflow: "ellipsis"}}
                    paragraph={true}
                    align="center"
                    variant="subtitle2"
                >
                    "At vero eos et accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus accusamus et iusto odio dignissimos ducimus qui blanditiis praesentium voluptatum deleniti atque corrupti quos dolores et quas At vero eos et accusamus et iusto odio dignissimos ducimus qui blanditiis praesentium voluptatum deleniti atque corrupti quos dolores et quas"
                </Typography>
            </Stack>
        </Box>
    </Paper>
    )
}

function ResearchViewSkeleton() {
    return (
    <Paper sx={{borderRadius: "8px"}}>
        <Box sx={{maxWidth:"fit-content"}}>
            <Stack id="researchContent" direction="column" spacing={1}>
                <a id="researchImage" href="#researchSegment">
                    <Skeleton variant="rectangular" width={256} height={256} sx={{borderRadius: "5%"}}/>
                </a>
                <Typography sx={{fontWeight: "bold", color: "text.primary", m:0}} align="left" variant="h6">
                    <Skeleton variant="text" width={224} sx={{padding: "4px"}}> Pending Update</Skeleton>
                </Typography>
                <Typography
                    sx={{color: "text.primary", textAlign:"justify"}}
                    paragraph={true}
                    align="center"
                    variant="subtitle2">
                    <Skeleton variant="rectangular" width={256} height={200} sx={{borderRadius: "5%"}}/>
                </Typography>
            </Stack>
        </Box>
    </Paper>
    )
}

function Research() {
    return (
    <Box>
        <Typography sx={{fontWeight: "bold", color: "text.primary", m:0, ml: 4, mb: 1}} align="left" variant="h4">Research</Typography>
        <div className="scroll">
            <Stack alignItems="center" direction="column" spacing={4}>
                <Stack direction="row" spacing={8}>
                    <ResearchViewSkeleton/>
                    <ResearchViewSkeleton/>
                    <ResearchViewSkeleton/>
                    <ResearchViewSkeleton/>
                </Stack>
            </Stack>
        </div>
    </Box>
    )
}

export default Research