import React, {useState} from 'react';
import AppBar            from '@mui/material/AppBar';
import Box               from '@mui/material/Box';
import Toolbar           from '@mui/material/Toolbar';
import Typography        from '@mui/material/Typography';
import Container         from '@mui/material/Container';
import Button            from '@mui/material/Button';
import List              from '@mui/material/List';
import ListItem          from '@mui/material/ListItem';
import ListItemText      from '@mui/material/ListItemText';
import ListItemAvatar    from '@mui/material/ListItemAvatar';
import Avatar            from '@mui/material/Avatar';
import {Link}            from "react-scroll";
import {Stack}           from "@mui/material";

import logo from "../assets/placeholder.png"
import "./Navbar.css"


function Navbar() {
    const [nav, setnav] = useState(false)
    const changeBackground = () => {
        if(window.scrollY >= 60)  {
            setnav(true)
        } else {
            setnav(false)
        }
    }
    window.addEventListener('scroll', changeBackground)


    return (
        <AppBar id={nav ? "nav-active" : "nav"} sx={{bgcolor: "background.paper"}}>
            <Container disableGutters sx={{ width: "98vw", maxWidth: "98vw", bgcolor: 'transparent', padding: 0, margin: 0}}>
                <Toolbar disableGutters sx={{ width: "98vw", maxWidth: "98vw", bgcolor: 'transparent', padding: 0, margin: 0}}>
                    <List sx={{ width: '100%',  maxWidth: 360, padding: 0, bgcolor: 'transparent' }}>
                        <ListItem sx={{ height: '64px', padding: "4px 4px"}}>
                            <ListItemAvatar sx={{ width: '64px', height: '64px', padding: "4px 4px"}}>
                                <Avatar src={logo} alt="O" sx={{ border: 2, borderColor: 'secondary.main', width: '56px', height: '56px', padding: 0, margin: 0}}/>
                            </ListItemAvatar>
                            <ListItemText
                                primary={
                                    <Link spy={true} smooth={true} duration={400} to="homeSection" >
                                        <Typography variant="body1" sx={{ fontWeight: "900", color: 'secondary.main' }}>Ommar Shaikh</Typography>
                                    </Link>
                                }
                                secondary={
                                    <Link spy={true} smooth={true} duration={400} to="aboutSection" >
                                        <Typography variant="caption" sx={{ fontWeight: "400", color: 'text.primary' }}>Full Stack Developer</Typography>
                                    </Link>
                                }
                            />
                        </ListItem>
                    </List>
                    <Box sx={{ position: "absolute", right:0, display: { xs: 'none', md: 'flex' } }}>
                        <Stack direction="row" spacing={2}>
                            <Link spy={true} smooth={true} duration={400} to="homeSection" >
                                <Button size="large" color="secondary">Home</Button>
                            </Link>
                            <Link spy={true} smooth={true} duration={400} to="aboutSection" >
                                <Button size="large" color="secondary">About</Button>
                            </Link>
                            <Link spy={true} smooth={true} duration={400} to="projectSection" >
                                <Button size="large" color="secondary">Projects</Button>
                            </Link>
                            <Link spy={true} smooth={true} duration={400} to="researchSection" >
                                <Button size="large" color="secondary">Research</Button>
                            </Link>
                            <Link spy={true} smooth={true} duration={400} to="contactsSection" >
                                <Button size="large" color="secondary">Contacts</Button>
                            </Link>
                        </Stack>
                    </Box>
                </Toolbar>
            </Container>
        </AppBar>
    )
}
export default Navbar
