import React    from "react";
import Navbar   from "./Navbar";
import Home     from "./sections/Home";
import Intro    from "./sections/Intro";
import About    from "./sections/About";
import Project  from "./sections/Project";
import Research from "./sections/Research";
import Contacts from "./sections/Contacts";

import './Header.css'
import {Box} from "@mui/material";


function Header() {
    return (
        <Box id='main'>
            <Navbar/>
            <Box className="content">
                <Box className='introSection' id='introSection' role='region'>
                    <Intro/>
                </Box>
                <Box className='homeSection' id='homeSection' role='region'>
                    <Home/>
                </Box>
                <Box className='aboutSection' id='aboutSection' role='region'>
                    <About/>
                </Box>
                <Box className='projectSection' id='projectSection' role='region'>
                    <Project/>
                </Box>
                <Box className='researchSection' id='researchSection' role='region'>
                    <Research/>
                </Box>
                <Box className='contactsSection' id='contactsSection' role='region'>
                    <Contacts/>
                </Box>
            </Box>
        </Box>
    )
}

export default Header