import {createTheme} from "@mui/material/styles";
import createPalette from "@mui/material/styles/createPalette";


export const portfolioTheme = createTheme({
    palette: createPalette({
        primary: {
            main: '#3C3D3E',
        },
        secondary: {
            main: '#ffd700',
        },
        background: {
            paper: '#202020',
            default: '#0c0d0d',
        },
        text: {
            primary: '#ececec',
        },
    })
});