import React, {SyntheticEvent, useState}          from "react";
import {Box, Chip, IconButton, Paper, Stack, Typography} from "@mui/material";
import rightArrow                                 from "../../assets/right_arrow.svg"
import leftArrow                                  from "../../assets/left_arrow.svg"
import './Project.css'
import {ProjectInfoDict, ProjectItemParams} from "./ProjectInfoDict";


let itemIndex = 0

function ProjectItem({Name, ProjectLink, Image, Links, Content}: ProjectItemParams) {
    console.log("ProjectItem: Loaded", Name)
    const Chips = Links.map((link) =>
        <a target="_blank" rel="noreferrer noopener" href={link.link}>
            <Chip
                clickable
                key={link.key}
                variant="outlined"
                label={link.label}
                sx={{textAlign:"justify", maxWidth:"96px", overflow: "hidden", textOverflow: "ellipsis"}}
            />
        </a>
    )
    return (
    <Stack direction="row" id="projectContent" spacing={2} width={"90vw"} maxWidth={"90vw"}>
        <Paper>
            <a href={ProjectLink} target="_blank" rel="noreferrer noopener">
                <Box id="projectView">
                    <img id="ProjectImage" src={Image} alt=""/>
                </Box>
            </a>
        </Paper>
        <Stack direction="column" id="projectDesc" spacing={1}>
            <a href={ProjectLink} target="_blank" rel="noreferrer noopener">
                <Typography sx={{fontWeight: "bold", color: "secondary.main", m:0}} align="left" variant="h4">{Name}</Typography>
            </a>
            <Stack id="projectLinkButtons" direction="row" spacing={1}>
                {Chips}
            </Stack>
            <br/>
            <Typography sx={{color: "text.primary", textAlign:"justify"}} paragraph={true} align="center" variant="subtitle2">
                {Content}
            </Typography>
        </Stack>
    </Stack>
    )
}

function Project() {
    const [ProjectItemLoaded, setProjectItemLoaded] = useState(
        <ProjectItem
            Name={ProjectInfoDict[itemIndex].Name}
            ProjectLink={ProjectInfoDict[itemIndex].ProjectLink}
            Image={ProjectInfoDict[itemIndex].Image}
            Links={ProjectInfoDict[itemIndex].Links}
            Content={ProjectInfoDict[itemIndex].Content} 
        />
    )

    function loadNextProjectInfo() {
        console.log(itemIndex)
        if ((0 <= itemIndex) && (itemIndex < (ProjectInfoDict.length - 1))) {
            itemIndex ++
        } else if (itemIndex === (ProjectInfoDict.length - 1)) {
            itemIndex = 0
        } else {
            console.error("loadNextProjectInfo")
            return null
        }
        setProjectItemLoaded(
            <ProjectItem
                Name={ProjectInfoDict[itemIndex].Name}
                ProjectLink={ProjectInfoDict[itemIndex].ProjectLink}
                Image={ProjectInfoDict[itemIndex].Image}
                Links={ProjectInfoDict[itemIndex].Links}
                Content={ProjectInfoDict[itemIndex].Content}
            />
        )
    }

    function loadPrevProjectInfo() {
        if ((0 < itemIndex) && (itemIndex <= (ProjectInfoDict.length - 1))) {
            itemIndex --
        } else if (itemIndex === 0) {
            itemIndex = (ProjectInfoDict.length - 1)
        } else {
            console.error("loadPrevProjectInfo", itemIndex)
            return null
        }
        setProjectItemLoaded(
            <ProjectItem
                Name={ProjectInfoDict[itemIndex].Name}
                ProjectLink={ProjectInfoDict[itemIndex].ProjectLink}
                Image={ProjectInfoDict[itemIndex].Image}
                Links={ProjectInfoDict[itemIndex].Links}
                Content={ProjectInfoDict[itemIndex].Content}
            />
        )
    }

    function handleClick(event: SyntheticEvent, type: string) {
        if (type === "Left") {
            loadPrevProjectInfo()
        } else if (type === "Right") {
            loadNextProjectInfo()
        } else {
            console.error(type)
        }
    }

    return (
        <Stack id="ProjectContents" spacing={2} direction="row" sx={{alignItems: "center", p: 1}}>
            <IconButton
                color="secondary"
                id="leftButton"
                onClick={(e) => handleClick(e, "Left")}
                sx={{width: "48px", height: "48px", minWidth: "48px", minHeight: "48px", padding: "4px"}}>
                <img alt="" src={leftArrow}/>
            </IconButton>
            {ProjectItemLoaded}
            <IconButton
                color="secondary"
                id="rightButton"
                onClick={(e) => handleClick(e, "Right")}
                sx={{width: "48px", height: "48px", minWidth: "48px", minHeight: "48px", padding: "4px"}}>
                <img alt="" src={rightArrow}/>
            </IconButton>
        </Stack>
    )
}

export default Project