import React, {SyntheticEvent, useState}                                   from "react";
import {Alert, Box, Button, Paper, Snackbar, Stack, TextField, Typography} from "@mui/material";
import './Contacts.css';
import gmaillogo                                                           from "../../assets/google-gmail.svg";
import linkedinlogo                                                        from "../../assets/linkedin-icon.svg";
import twitterlogo                                                         from "../../assets/twitter.svg";
import instalogo                                                           from "../../assets/instagram-icon.svg";
import gitlogo                                                             from "../../assets/github-octocat.svg";


function Contacts() {
    const [name, setName] = useState("")
    const [email, setEmail] = useState("")
    const [subject, setSubject] = useState("")
    const [message, setMessage] = useState("")
    const [alert, setAlert] = useState(<div/>)
    const [alertOpen, setAlertOpen] = useState(false)

    const handleCloseAlert = (event?: React.SyntheticEvent | Event, reason?: string) => {
        setAlertOpen(false);
    };

    function sendMail(event: SyntheticEvent, name: string, email: string, subject: string, message: string ) {
        name = name.trim()
        email = email.trim()
        subject = subject.trim()
        message = message.trim()
        if (!((name === "") || (email === "") || (subject === "") || (message === ""))) {
            console.log(name, email, subject, message)
            setAlert(<Alert onClose={handleCloseAlert} sx={{ width: '100%' }} severity="success">Email Sent</Alert>)
            setAlertOpen(true)
        } else {
            if (name === "") {
                setAlert(<Alert onClose={handleCloseAlert} sx={{ width: '100%' }} severity="error">Input Correct Name</Alert>)
                setAlertOpen(true)
                return null
            }
            if (email === "") {
                setAlert(<Alert onClose={handleCloseAlert} sx={{ width: '100%' }} severity="error">Input Correct Email</Alert>)
                setAlertOpen(true)
                return null
            }
            if (subject === "") {
                setAlert(<Alert onClose={handleCloseAlert} sx={{ width: '100%' }} severity="error">Input Correct Subject</Alert>)
                setAlertOpen(true)
                return null
            }
            if (message === "") {
                setAlert(<Alert onClose={handleCloseAlert} sx={{ width: '100%' }} severity="error">Input Correct Message</Alert>)
                setAlertOpen(true)
                return null
            }
        }
    }

    return (
        <Box className='contacts'>
            <Snackbar onClose={handleCloseAlert} open={alertOpen} autoHideDuration={2000} >
                {alert}
            </Snackbar>
            <Stack spacing={2} direction="column" id='contactsContainer' sx={{width: "98vw", padding: "8px"}}>
                <Typography
                    sx={{width: "100%", fontWeight: "bold", color: "text.primary", m: 0, pl: "16px"}}
                    align="left"
                    variant="h4"
                >
                    Contacts
                </Typography>
                <Stack alignItems="center" justifyContent="center" spacing={12} direction="row">
                    <Box>
                        <a target="_blank" rel="noreferrer noopener"href="https://www.linkedin.com/in/ommar-shaikh-0a4a21229/"><img width="96px" height="96px" src={linkedinlogo} alt=""/></a>
                        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant="h6" id="LINKEDIN">LINKEDIN</Typography>
                    </Box>
                    <Box>
                        <a target="_blank" rel="noreferrer noopener"href="mailto:ommarshaikh20@gmail.com"><img width="96px" height="96px" src={gmaillogo} alt=""/></a>
                        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant="h6" id="GMAIL">GMAIL</Typography>
                    </Box>
                    <Box>
                        <a target="_blank" rel="noreferrer noopener"href="https://github.com/OmmarShaikh01"><img width="96px" height="96px" src={gitlogo} alt=""/></a>
                        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant="h6" id="GITHUB">GITHUB</Typography>
                    </Box>
                    <Box>
                        <a target="_blank" rel="noreferrer noopener"href="https://twitter.com/ommarshaikh20"><img width="96px" height="96px" src={twitterlogo} alt=""/></a>
                        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant="h6" id="TWITTER">TWITTER</Typography>
                    </Box>
                    <Box>
                        <a target="_blank" rel="noreferrer noopener"href="https://www.instagram.com/ommarshaikh20/"><img width="96px" height="96px" src={instalogo} alt=""/></a>
                        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="center" variant="h6" id="INSTAGRAM">INSTAGRAM</Typography>
                    </Box>
                </Stack>
            </Stack>
            <Stack justifyItems="center" alignItems="center" sx={{width: "98vw", padding: "8px"}} spacing={2}>
                <Typography
                    sx={{width: "100%", fontWeight: "bold", color: "text.primary", m: 0, pl: "16px"}}
                    align="left"
                    variant="h4"
                >
                    Contact Me
                </Typography>
                <Stack sx={{width: "90vw"}} justifyItems="center" alignItems="center" spacing={2}>
                    <Stack justifyItems="center" alignItems="center" direction="row" spacing={2} sx={{width: "100%"}}>
                        <Paper sx={{width:"100%"}}>
                            <TextField
                                type="text" id="username" placeholder='name' color="secondary" fullWidth variant="outlined" name="username"
                                onChange={(e) => setName(e.target.value)}
                            />
                        </Paper>
                        <Paper sx={{width:"100%"}}>
                            <TextField
                                type="text" id="useremail" placeholder='email' color="secondary" fullWidth variant="outlined" name="useremail"
                                onChange={(e) => setEmail(e.target.value)}
                            />
                        </Paper>
                    </Stack>
                    <Paper sx={{width:"100%"}}>
                        <TextField
                            type="text" id="usersubject" placeholder='subject' color="secondary" fullWidth variant="outlined" name="usersubject"
                            onChange={(e) => setSubject(e.target.value)}
                        />
                    </Paper>
                    <Paper sx={{width:"100%"}}>
                        <TextField
                            type="text" id="usermessage" placeholder='message' color="secondary" fullWidth variant="outlined" name="usermessage" multiline maxRows={4}
                            onChange={(e) => setMessage(e.target.value)}
                        />
                    </Paper>
                    <Button
                        variant="outlined" size="large" color="secondary" sx={{width: "128px", maxWidth: "128px"}}
                        onClick={(e) => sendMail(e, name, email, subject, message)}
                    >
                        Send
                    </Button>
                </Stack>
            </Stack>
        </Box>
    )
}

export default Contacts