import {Avatar, Box, Stack, Typography} from "@mui/material";
import React                            from "react";
import './About.css'

function AboutMe() {
    return (<Box id="aboutMe">
        <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="left" variant="h4">About Me</Typography>
        <Typography sx={{width: "35vw", color: "text.primary"}} paragraph={true} align="center" variant="body1">
            I'm <mark>Ommar Shaikh</mark> a <mark>Full stack developer</mark> living in india. My 2 years of
            experience has given me a strong foundation On building complex solutions. I am graduating from Mumbai
            University with a Bachlors in <mark>Computer science</mark>. I have Creative experience in
            making <mark>Android, Web and Desktop Apps</mark>. Mostly my contributions are in <mark>open source And
            research projects</mark>. I am passionate about coding and solving problems through code, and I am
            excited to work alongside other amazing programmers and learn so much more !
        </Typography>
    </Box>)
}

function Skills() {
    const avatarSX = {border: 1, borderColor: "secondary.main", width: "96px" ,height: "96px", margin: "8px", padding: "12px", borderRadius: "15%"}
    return (<Box id="skills" sx={{ width:"35vw", display: { xs: 'flex', md: 'flex' } }}>
        <Stack>
            <Typography sx={{fontWeight: "bold", color: "text.primary", m:1}} align="left" variant="h4">Skills</Typography>
            <Stack direction="row">
                <Stack>
                    <a target="_blank" rel="noreferrer noopener" href="https://kotlinlang.org">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/kotlin/kotlin-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://firebase.google.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/firebase/firebase-plain.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.android.com/intl/en_in/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/android/android-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://gradle.org/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/gradle/gradle-plain.svg"
                                alt=""/>
                    </a>
                </Stack>
                <Stack>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.python.org/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/python/python-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.qt.io/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/qt/qt-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.djangoproject.com">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/django/django-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.jetbrains.com/pycharm/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/pycharm/pycharm-original-wordmark.svg"
                                alt=""/>
                    </a>
                </Stack>
                <Stack>
                    <a target="_blank" rel="noreferrer noopener" href="https://reactjs.org/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/react/react-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://sass-lang.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/sass/sass-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://mui.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/materialui/materialui-plain.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.jetbrains.com/webstorm/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/webstorm/webstorm-original-wordmark.svg"
                                alt=""/>
                    </a>
                </Stack>
                <Stack>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.mysql.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/mysql/mysql-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.npmjs.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/npm/npm-original-wordmark.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://www.figma.com">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/figma/figma-original.svg"
                                alt=""/>
                    </a>
                    <a target="_blank" rel="noreferrer noopener" href="https://git-scm.com/">
                        <Avatar sx={avatarSX} variant="square"
                                src="https://cdn.jsdelivr.net/gh/devicons/devicon/icons/git/git-plain.svg" alt=""/>
                    </a>
                </Stack>
            </Stack>
        </Stack>
    </Box>)
}

function About() {
    return (
        <Box id="aboutContent">
            <Stack spacing={16} direction="row">
                <AboutMe/>
                <Skills/>
            </Stack>
        </Box>
    )
}

export default About